+    let source = PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("src/control_plane/mod.rs");
+    let content = fs::read_to_string(&source)
+        .unwrap_or_else(|err| panic!("read {}: {err}", source.display()));
